package owner.mysafefloridahome.vendor;

public class OpeningProtectionOfficePresetRequest {
    private String presetId;
    private String presetName;
    private String officeLabel;
    private String senderName;
    private String replyInstructions;
    private String serviceAreaNote;
    private String permitHandlingNote;
    private String attachedScopeNote;
    private String boundaryScopeNote;

    public String getPresetId() {
        return presetId;
    }

    public void setPresetId(String presetId) {
        this.presetId = presetId;
    }

    public String getPresetName() {
        return presetName;
    }

    public void setPresetName(String presetName) {
        this.presetName = presetName;
    }

    public String getOfficeLabel() {
        return officeLabel;
    }

    public void setOfficeLabel(String officeLabel) {
        this.officeLabel = officeLabel;
    }

    public String getSenderName() {
        return senderName;
    }

    public void setSenderName(String senderName) {
        this.senderName = senderName;
    }

    public String getReplyInstructions() {
        return replyInstructions;
    }

    public void setReplyInstructions(String replyInstructions) {
        this.replyInstructions = replyInstructions;
    }

    public String getServiceAreaNote() {
        return serviceAreaNote;
    }

    public void setServiceAreaNote(String serviceAreaNote) {
        this.serviceAreaNote = serviceAreaNote;
    }

    public String getPermitHandlingNote() {
        return permitHandlingNote;
    }

    public void setPermitHandlingNote(String permitHandlingNote) {
        this.permitHandlingNote = permitHandlingNote;
    }

    public String getAttachedScopeNote() {
        return attachedScopeNote;
    }

    public void setAttachedScopeNote(String attachedScopeNote) {
        this.attachedScopeNote = attachedScopeNote;
    }

    public String getBoundaryScopeNote() {
        return boundaryScopeNote;
    }

    public void setBoundaryScopeNote(String boundaryScopeNote) {
        this.boundaryScopeNote = boundaryScopeNote;
    }
}
